var liveCommand = new Composer();
liveCommand.command("live", async (ctx) => {
  const chatId = ctx.chat?.id;
  if (!chatId) return;
  const chat = await ctx.services.chatRepo.findByChatId(chatId, "telegram");
  if (!chat) return;
  const follows2 = await ctx.services.followRepo.findByChatId(chat.id);
  if (follows2.length === 0) {
    await ctx.reply("You are not following any channels.");
    return;
  }
  const channelIds = [];
  for (const follow of follows2) {
    const channel = await ctx.services.channelRepo.findById(follow.channelId);
    if (channel) {
      channelIds.push(channel.channelId);
    }
  }
  if (channelIds.length === 0) {
    await ctx.reply("No channels found.");
    return;
  }
  const liveChannels = [];
  for (const channelId of channelIds) {
    const stream = await ctx.services.twitch.getStreamByUserId(channelId);
    if (stream) {
      const user = await ctx.services.twitch.getUserById(channelId);
      if (user) {
        liveChannels.push({
          name: user.displayName,
          login: user.name,
          startedAt: stream.startDate,
          title: stream.title,
          category: stream.gameName,
          viewers: stream.viewers
        });
      }
    }
  }
  if (liveChannels.length === 0) {
    await ctx.reply("No one is online.");
    return;
  }
  const messages = [];
  for (const channel of liveChannels) {
    const channelMessage = [];
    channelMessage.push(
      `\u{1F7E2} <a href="https://twitch.tv/${channel.login}">${channel.name}</a> - ${channel.viewers} \u{1F441}\uFE0F\uFE0F`
    );
    if (channel.category) {
      channelMessage.push(`\u{1F3AE} ${channel.category}`);
    }
    if (channel.title) {
      channelMessage.push(`\u{1F4DD} ${channel.title}`);
    }
    const uptime2 = Date.now() - channel.startedAt.getTime();
    const hours = Math.floor(uptime2 / 36e5);
    const minutes = Math.floor(uptime2 % 36e5 / 6e4);
    const seconds = Math.floor(uptime2 % 6e4 / 1e3);
    let uptimeStr = "\u231B ";
    if (hours > 0) uptimeStr += `${hours}h `;
    if (minutes > 0) uptimeStr += `${minutes}m `;
    if (seconds > 0) uptimeStr += `${seconds}s `;
    channelMessage.push(uptimeStr);
    messages.push(channelMessage.join("\n"));
  }
  await ctx.reply(messages.join("\n\n"), {
    parse_mode: "HTML",
    link_preview_options: { is_disabled: true }
  });
});

